/** True when this MAP_TRAINERS id is already painted into the area crop. */
export function isBakedOutdoorTrainer(areaId: string | undefined, trainerId: string): boolean {
  if (!areaId) return false;
  const list = HOENN_CROP_CUTSCENE_ENTITIES[areaId];
  if (!list) return false;
  return list.some((e) => e.sourceTrainerId === trainerId || e.id === `crop-${trainerId}`);
}
